class Rum():

  def __init__(self, storlek, fönster, uthyrt=False):
    self.storlek = storlek
    self.antal_fönster = fönster
    self.uthyrt = uthyrt

  def __str__(self):
    if self.uthyrt:
      sträng = "Rummet är uthyrt, "
    else:
      sträng = "Rummet är ledigt, "

    return sträng + str(self.storlek) + " kvm stort och har " + str(self.antal_fönster) + " fönster."

  def hyr_ut(self):
    self.uthyrt = True

  def är_ledigt(self):
    self.uthyrt = False

from rum import *

class Hus:
  def __init__(self, adress, lista_rum):
    self.adress = adress
    self.rum_lista = lista_rum

  def __str__(self):
    sträng = "Huset ligger på " + self.adress + "."
    sträng += "\nDet har " + str(len(self.rum_lista)) + " antal rum:\n"
    for i in range(len(self.rum_lista)):
      sträng += str(i+1) + ". " + str(self.rum_lista[i]) + "\n"
    return sträng
